import '@ds-mo/ui/dist/components/ds-shell-app.js'
import '@ds-mo/ui/dist/components/ds-shell-page.js'
import '@ds-mo/ui/dist/components/ds-bar-title.js'

const header = document.querySelector<HTMLDsBarTitleElement>('#drivers-header')!
header.sections = [
  { id: 'active', label: 'Active' },
  { id: 'inactive', label: 'Inactive' },
]
header.primaryAction = { id: 'create', label: 'Create driver' }
header.addEventListener('dsSectionChange', event => {
  const value = (event as CustomEvent<string>).detail
  // Update the route, then pass the resolved route value back to the header.
  header.value = value
})

import { useState } from 'react'
import { DsShellApp, DsBarTitle, DsShellPage } from '@ds-mo/ui/react'

const sections = [
  { id: 'active', label: 'Active' },
  { id: 'inactive', label: 'Inactive' },
]

export function DriversPage() {
  const [value, setValue] = useState('active')
  return (
    <DsShellApp>
      <DsShellPage headerCapacity="roomy">
        <DsBarTitle
          slot="header"
          heading="Drivers"
          sections={sections}
          value={value}
          primaryAction={{ id: 'create', label: 'Create driver' }}
          onDsSectionChange={event => setValue(event.detail)}
        />
        <section aria-label="Driver results">Page content</section>
      </DsShellPage>
    </DsShellApp>
  )
}

import { Component } from '@angular/core'
import { RouterOutlet } from '@angular/router'
import type { ShellPageCapacity } from '@ds-mo/ui'
import { DsBarTitle } from '@ds-mo/ui/angular/ds-bar-title'
import { DsShellPage } from '@ds-mo/ui/angular/ds-shell-page'

@Component({
  standalone: true,
  imports: [DsBarTitle, DsShellPage, RouterOutlet],
  templateUrl: './drivers-page.component.html',
})
export class DriversPageComponent {
  readonly headerCapacity: ShellPageCapacity = 'roomy'
  readonly sections = [
    { id: 'active', label: 'Active' },
    { id: 'inactive', label: 'Inactive' },
  ]
  readonly primaryAction = { id: 'create', label: 'Create driver' }
  selectedSection = 'active'

  selectSection(id: string) {
    this.selectedSection = id
    // Navigate to the matching child route.
  }
}
